    hierarchy_levels = {}
    subordinate_counts = {}
    manager_chains = {}

    # Build the hierarchy
    for employee_id, employee_name, manager_id in employees:
        if manager_id is None:
            level = 1
        else:
            level = hierarchy_levels[manager_id] + 1
        hierarchy_levels[employee_id] = level

    # Count subordinates
    for employee_id, employee_name, manager_id in employees:
