import collections

def get_hierarchy_levels(employees):
    levels = {}
    for employee_id, employee_name, manager_id in employees:
        level = 1
        while manager_id is not None:
            level += 1
            for emp_id, emp_name, mgr_id in employees:
                if emp_id == manager_id:
                    manager_id = mgr_id
                    break
        levels[employee_id] = level
    return levels

def get_subordinate_count(employees):
    subordinates = collections.defaultdict(list)
    for employee_id, employee_name, manager_id in employees:
        if manager_id is not None:
            subordinates[manager_id].append(employee_id)

    subordinate_count = {}
    for employee_id, employee_name, _ in employees:
        count = 0
        queue = subordinates[employee_id]
        while queue:
            subordinate = queue.pop(0)
            count += 1
            queue.extend(subordinates[subordinate])
        subordinate_count[employee_id] = count
    return subordinate_count

def get_manager_chain(employees):
    manager_chain = {}
    levels = get_hierarchy_levels(employees)
    for employee_id, employee_name, manager_id in employees:
        chain = []
        level = levels[employee_id]
        while level > 1:
            for emp_id, emp_name, mgr_id in employees:
                if emp_id == manager_id:
                    chain.append(emp_name)
                    manager_id = mgr_id
                    level -= 1
                    break
        manager_chain[employee_id] = '> '.join(reversed(chain))
    return manager_chain

