def employee_hierarchy(employees):
    employee_map = {}
    for employee in employees:
        employee_map[employee[0]] = {
            'name': employee[1],
            'manager_id': employee[2],
            'level': 0,
            'subordinate_count': 0,
            'manager_chain': []
        }

    for employee_id, employee_data in employee_map.items():
        manager_id = employee_data['manager_id']
        if manager_id is None:
            employee_data['level'] = 1
        else:
            manager_data = employee_map[manager_id]
            employee_data['level'] = manager_data['level'] + 1
            manager_data['subordinate_count'] += 1
            employee_data['manager_chain'] = manager_data['manager_chain'] + [manager_data['name']]

    return [
        {'employee_id': employee_id, 'employee_name': employee_data['name'], 'level': employee_data['level']},
        {'employee_id': employee_id, 'employee_name': employee_data['name'], 'subordinate_count': employee_data['subordinate_count']},
        {'employee_id': employee_id, 'employee_name': employee_data['name'], 'manager_chain': '> '.join(employee_data['manager_chain'])}
    ]

import collections

def employee_hierarchy(employees):
    hierarchy_levels = {}
    subordinate_counts = {}
    manager_chains = {}

    # Build the hierarchy and compute subordinate counts
    def dfs(employee_id, level=1):
        hierarchy_levels[employee_id] = level
        subordinate_counts[employee_id] = 0

        for subordinate_id in [e for e in employees if e["manager_id"] == employee_id]:
            subordinate_counts[employee_id] += 1
            subordinate_counts[subordinate_id] = dfs(subordinate_id, level + 1)

        return subordinate_counts[employee_id]

    # Compute the manager chain
    for employee in employees:
        employee_id = employee["employee_id"]
        manager_id = employee["manager_id"]
        manager_chain = [employee_id]

        while manager_id is not None:
            manager_chain.append(manager_id)
            manager_id = next((e["manager_id"] for e in employees if e["employee_id"] == manager_id), None)

        manager_chains[employee_id] = ">".join(map(str, reversed(manager_chain)))

    # Run the DFS to compute hierarchy levels and subordinate counts
    for employee in employees:
        if employee["manager_id"] is None:
            dfs(employee["employee_id"])

    return hierarchy_levels, subordinate_counts, manager_chains

