def soln(employees, hierarchy, salaries):
    # Initialize the data structures
    num_employees = len(employees)
    emp_to_level = {emp: level for level, emp in enumerate(employees)}
    level_to_emp = {level: [emp] for level, emp in enumerate(employees)}

