    for subordinate, boss in hierarchy:
        level_to_emp[emp_to_level[boss]].append(subordinate)
        emp_to_level[subordinate] = emp_to_level[boss] + 1

    # Process the salaries data
    for employee, salary in salaries:
        level_to_emp[emp_to_level[employee]].append(salary)

    # Compute the results
    result = []
    for level in range(len(level_to_emp)):
