import random

class Employee:
    def __init__(self, name, level, reports_to):
        self.name = name
        self.level = level
        self.reports_to = reports_to

def create_org_chart(employees):
    org_chart = {}
    for employee in employees:
        if employee.level not in org_chart:
            org_chart[employee.level] = []
        org_chart[employee.level].append(employee)
    return org_chart

def print_org_chart(org_chart):
    for level, employees in sorted(org_chart.items()):
        print(f"* * {'-' * (10 - len(str(level)))}Level {level}{'-' * (10 - len(str(level)))} * *")
        print("| Employee | Reports To |")
        print("| --- | --- |")
        for employee in employees:
            print(f"| {employee.name} | {employee.reports_to} |")
        print()

def generate_employees():
    names = ["Alice", "Bob", "Charlie", "David", "Eve", "Frank"]
    levels = [1, 2, 3]
    employees = []
    for i, name in enumerate(names):
        level = random.choice(levels)
        if level == 1:
            reports_to = "CEO"
        else:
            reports_to = random.choice([e for e in employees if e.level == level - 1]).name
        employees.append(Employee(name, level, reports_to))
    return employees

employees = generate_employees()
org_chart = create_org_chart(employees)
print_org_chart(org_chart)

