import csv

def print_org_chart(file_path):
    with open(file_path, 'r') as file:
        reader = csv.DictReader(file, delimiter='|')
        data = list(reader)

    def print_level(level, prefix):
        for row in data:
            if int(row['Level']) == level:
                print(f"{prefix}{row['Name']} ({row['Title']})")
                print_level(level + 1, f"{prefix}  ")

    print_level(1, '')

def print_salaries(file_path):
    with open(file_path, 'r') as file:
        reader = csv.DictReader(file, delimiter='|')
        data = list(reader)

    for row in data:
        print(f"{row['Name']} ({row['Salary']})")

def print_reporting_structure(file_path):
    with open(file_path, 'r') as file:
        reader = csv.DictReader(file, delimiter='|')
        data = list(reader)

    for row in data:
        report_to = row['ReportsTo']
        if report_to == 'CEO':
            print(f"{row['Name']} reports to the CEO")
        else:
            for manager in data:
                if manager['Name'] == report_to:
                    print(f"{row['Name']} reports to {manager['Name']}")
                    break

