def soln1():
    employees = {}
    with open('employees.txt', 'r') as f:
        for line in f:
            name, level, manager = line.strip().split(',')
            if manager == 'CEO':
                manager_level = 1
            else:
                manager_level = employees[manager][1] + 1
            employees[name] = (manager, manager_level)
    return employees

def soln2():
