        for line in f:
            name, budget, duration, manager = line.strip().split(',')
            projects[name] = (int(budget), int(duration), manager)
    return projects

def soln3():
    emp_project = {}
    with open('assignments.txt', 'r') as f:
        for line in f:
            emp, proj = line.strip().split(',')
            if emp not in emp_project:
                emp_project[emp] = [proj]
            else:
                emp_project[emp].append(proj)
    return emp_project

